                        {
                            <tr class="@(appt.Status == AppointmentStatus.Cancelled ? "table-secondary text-decoration-line-through" : "")">
                                <td>@appt.StartTime.ToString("HH:mm") - @appt.EndTime.ToString("HH:mm")</td>
                                <td>@appt.Patient.Name</td>
