                                <td>@appt.Reason</td>
                                <td>@appt.VeterinarianName</td>
                                <td><span class="badge @GetStatusBadge(appt.Status)">@appt.Status</span></td>
                                <td>
                                    @if (appt.Status == AppointmentStatus.Scheduled)
                                    {
                                        <a href="/appointments/@appt.Id/edit" class="btn btn-sm btn-outline-primary">Reschedule</a>
                                        <button class="btn btn-sm btn-outline-danger" @onclick="() => CancelAsync(appt.Id)">Cancel</button>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            }
            else
            {
                <p class="text-muted ms-3">No appointments</p>
            }
        </div>
    }
</div>

@code {
    private List<Appointment> appointments = new();
    private DateTime selectedDate = DateTime.Today;
    private DateTime weekStart => selectedDate.AddDays(-(int)selectedDate.DayOfWeek);

    protected override async Task OnInitializedAsync()
    {
        await LoadAppointmentsAsync();
    }

    private async Task LoadAppointmentsAsync()
    {
        var start = weekStart;
        appointments = await Clinic.GetAppointmentsAsync(start, start.AddDays(7));
    }

    private async Task CancelAsync(int id)
    {
        await Clinic.CancelAppointmentAsync(id);
        await LoadAppointmentsAsync();
    }

    private string GetStatusBadge(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-success",
        AppointmentStatus.Completed => "bg-info",
        AppointmentStatus.Cancelled => "bg-secondary",
        _ => "bg-secondary"
    };
}
