### 3. Create Services — `/Services/` folder:

**ClinicService.cs** — a single service handling all data operations:

```csharp
using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class ClinicService(ApplicationDbContext db)
{
    // --- Owners ---
    public async Task<List<Owner>> GetOwnersAsync(string? search = null)
    {
        var query = db.Owners.Include(o => o.Patients).AsQueryable();
        if (!string.IsNullOrWhiteSpace(search))
            query = query.Where(o => o.LastName.Contains(search) || o.FirstName.Contains(search) || o.Phone.Contains(search));
        return await query.OrderBy(o => o.LastName).ToListAsync();
    }

    public async Task<Owner?> GetOwnerAsync(int id) =>
        await db.Owners.Include(o => o.Patients).FirstOrDefaultAsync(o => o.Id == id);

    public async Task SaveOwnerAsync(Owner owner)
    {
        if (owner.Id == 0) db.Owners.Add(owner);
        else db.Owners.Update(owner);
        await db.SaveChangesAsync();
    }

    // --- Patients ---
    public async Task<List<Patient>> GetPatientsAsync(string? search = null)
    {
        var query = db.Patients.Include(p => p.Owner).AsQueryable();
        if (!string.IsNullOrWhiteSpace(search))
            query = query.Where(p => p.Name.Contains(search) || p.Owner.LastName.Contains(search));
        return await query.OrderBy(p => p.Name).ToListAsync();
    }

    public async Task<Patient?> GetPatientAsync(int id) =>
        await db.Patients.Include(p => p.Owner).Include(p => p.TreatmentNotes.OrderByDescending(t => t.Date))
            .Include(p => p.Appointments.OrderByDescending(a => a.StartTime))
            .FirstOrDefaultAsync(p => p.Id == id);

    public async Task SavePatientAsync(Patient patient)
    {
        if (patient.Id == 0) db.Patients.Add(patient);
        else db.Patients.Update(patient);
        await db.SaveChangesAsync();
    }

    // --- Treatment Notes ---
    public async Task AddTreatmentNoteAsync(TreatmentNote note)
    {
        db.TreatmentNotes.Add(note);
        await db.SaveChangesAsync();
    }

    // --- Appointments ---
    public async Task<List<Appointment>> GetAppointmentsAsync(DateTime? from = null, DateTime? to = null)
    {
        var query = db.Appointments.Include(a => a.Patient).ThenInclude(p => p.Owner).AsQueryable();
        if (from.HasValue) query = query.Where(a => a.StartTime >= from.Value);
        if (to.HasValue) query = query.Where(a => a.StartTime <= to.Value);
        return await query.OrderBy(a => a.StartTime).ToListAsync();
    }

    public async Task<Appointment?> GetAppointmentAsync(int id) =>
        await db.Appointments.Include(a => a.Patient).ThenInclude(p => p.Owner).FirstOrDefaultAsync(a => a.Id == id);

    public async Task<bool> IsTimeSlotAvailableAsync(DateTime start, DateTime end, int? excludeAppointmentId = null)
    {
        var query = db.Appointments
            .Where(a => a.Status != AppointmentStatus.Cancelled)
            .Where(a => a.StartTime < end && a.EndTime > start);
        if (excludeAppointmentId.HasValue)
            query = query.Where(a => a.Id != excludeAppointmentId.Value);
        return !await query.AnyAsync();
    }

    public async Task SaveAppointmentAsync(Appointment appointment)
    {
        if (appointment.Id == 0) db.Appointments.Add(appointment);
        else db.Appointments.Update(appointment);
        await db.SaveChangesAsync();
    }

    public async Task CancelAppointmentAsync(int id)
    {
        var appt = await db.Appointments.FindAsync(id);
        if (appt != null)
        {
            appt.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
    }

    // --- Invoices ---
    public async Task<List<Invoice>> GetInvoicesAsync(InvoiceStatus? status = null)
    {
        var query = db.Invoices.Include(i => i.Owner).Include(i => i.Patient)
            .Include(i => i.Items).Include(i => i.Payments).AsQueryable();
        if (status.HasValue) query = query.Where(i => i.Status == status.Value);
        return await query.OrderByDescending(i => i.IssuedDate).ToListAsync();
    }

    public async Task<Invoice?> GetInvoiceAsync(int id) =>
        await db.Invoices.Include(i => i.Owner).Include(i => i.Patient)
            .Include(i => i.Items).Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == id);

    public async Task SaveInvoiceAsync(Invoice invoice)
    {
        if (invoice.Id == 0) db.Invoices.Add(invoice);
        else db.Invoices.Update(invoice);
        await db.SaveChangesAsync();
    }

    public async Task AddInvoiceItemAsync(InvoiceItem item)
    {
        db.InvoiceItems.Add(item);
        await db.SaveChangesAsync();
    }

    public async Task RemoveInvoiceItemAsync(int itemId)
    {
        var item = await db.InvoiceItems.FindAsync(itemId);
        if (item != null)
        {
            db.InvoiceItems.Remove(item);
            await db.SaveChangesAsync();
        }
    }

    // --- Payments ---
    public async Task<List<Payment>> GetPaymentsAsync(int? invoiceId = null)
    {
        var query = db.Payments.Include(p => p.Invoice).ThenInclude(i => i.Owner).AsQueryable();
        if (invoiceId.HasValue) query = query.Where(p => p.InvoiceId == invoiceId.Value);
        return await query.OrderByDescending(p => p.PaymentDate).ToListAsync();
    }

    public async Task ProcessPaymentAsync(Payment payment)
    {
        db.Payments.Add(payment);
        var invoice = await db.Invoices.Include(i => i.Items).Include(i => i.Payments).FirstOrDefaultAsync(i => i.Id == payment.InvoiceId);
        if (invoice != null)
        {
            var totalPaid = invoice.Payments.Where(p => p.IsSuccessful).Sum(p => p.Amount) + (payment.IsSuccessful ? payment.Amount : 0);
            if (totalPaid >= invoice.Items.Sum(i => i.Quantity * i.UnitPrice))
                invoice.Status = InvoiceStatus.Paid;
        }
        await db.SaveChangesAsync();
    }
}
```

