            <label class="form-label">Patient (optional)</label>
            <InputSelect class="form-select" @bind-Value="selectedPatientId">
                <option value="0">None</option>
                @foreach (var p in ownerPatients)
                {
                    <option value="@p.Id">@p.Name</option>
                }
            </InputSelect>
        </div>
        <div class="col-md-4 mb-3">
            <label class="form-label">Due Date</label>
            <InputDate class="form-control" @bind-Value="invoice.DueDate" />
        </div>
    </div>

    <h4 class="mt-3">Line Items</h4>
    <table class="table">
        <thead><tr><th>Description</th><th>Qty</th><th>Unit Price</th><th>Amount</th><th></th></tr></thead>
        <tbody>
            @for (int i = 0; i < items.Count; i++)
            {
                var idx = i;
                <tr>
                    <td><InputText class="form-control" @bind-Value="items[idx].Description" /></td>
                    <td><InputNumber class="form-control" style="width:80px" @bind-Value="items[idx].Quantity" /></td>
                    <td><InputNumber class="form-control" style="width:120px" @bind-Value="items[idx].UnitPrice" /></td>
                    <td>$@((items[idx].Quantity * items[idx].UnitPrice).ToString("F2"))</td>
                    <td><button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => items.RemoveAt(idx)">✕</button></td>
                </tr>
            }
        </tbody>
        <tfoot>
            <tr>
                <td colspan="3" class="text-end"><strong>Total:</strong></td>
                <td><strong>$@items.Sum(i => i.Quantity * i.UnitPrice).ToString("F2")</strong></td>
                <td></td>
            </tr>
        </tfoot>
    </table>
    <button type="button" class="btn btn-outline-secondary btn-sm" @onclick="AddItem">+ Add Item</button>

    <div class="mt-4">
        <button type="submit" class="btn btn-primary">Create Invoice</button>
        <a href="/billing" class="btn btn-secondary ms-2">Cancel</a>
    </div>
</EditForm>

@code {
    private Invoice invoice = new() { IssuedDate = DateTime.Today, DueDate = DateTime.Today.AddDays(30) };
    private List<InvoiceItem> items = new() { new InvoiceItem { Quantity = 1 } };
    private List<Owner> owners = new();
    private List<Patient> ownerPatients = new();
    private int selectedPatientId;

    protected override async Task OnInitializedAsync()
    {
        owners = await Clinic.GetOwnersAsync();
    }

    private void OnOwnerChanged()
    {
        var owner = owners.FirstOrDefault(o => o.Id == invoice.OwnerId);
        ownerPatients = owner?.Patients ?? new();
        selectedPatientId = 0;
    }

    private void AddItem() => items.Add(new InvoiceItem { Quantity = 1 });

    private async Task SaveAsync()
    {
        invoice.PatientId = selectedPatientId == 0 ? null : selectedPatientId;
        invoice.Status = InvoiceStatus.Issued;
        invoice.Items = items;
        await Clinic.SaveInvoiceAsync(invoice);
        Nav.NavigateTo($"/billing/{invoice.Id}");
    }
}
```

**InvoiceDetail.razor** — View invoice and process payments:
```razor
@page "/billing/{Id:int}"
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@using VetClinic.Services
@attribute [Authorize]
@inject ClinicService Clinic

<PageTitle>Invoice - VetClinic</PageTitle>

@if (invoice == null)
{
    <p>Loading...</p>
}
else
{
    <div class="d-flex justify-content-between align-items-center">
        <h1>Invoice INV-@invoice.Id.ToString("D4")</h1>
        <span class="badge @GetStatusBadge(invoice.Status) fs-6">@invoice.Status</span>
    </div>

    <div class="row mt-3">
        <div class="col-md-6">
            <p><strong>Owner:</strong> @invoice.Owner.FirstName @invoice.Owner.LastName</p>
            <p><strong>Patient:</strong> @(invoice.Patient?.Name ?? "N/A")</p>
        </div>
        <div class="col-md-6">
            <p><strong>Issued:</strong> @invoice.IssuedDate.ToShortDateString()</p>
            <p><strong>Due:</strong> @invoice.DueDate.ToShortDateString()</p>
        </div>
    </div>

    <h4 class="mt-3">Items</h4>
    <table class="table">
        <thead><tr><th>Description</th><th>Qty</th><th>Unit Price</th><th>Amount</th></tr></thead>
        <tbody>
            @foreach (var item in invoice.Items)
            {
                <tr>
                    <td>@item.Description</td>
                    <td>@item.Quantity</td>
                    <td>$@item.UnitPrice.ToString("F2")</td>
                    <td>$@item.Amount.ToString("F2")</td>
                </tr>
            }
        </tbody>
        <tfoot>
            <tr><td colspan="3" class="text-end"><strong>Total:</strong></td><td><strong>$@invoice.TotalAmount.ToString("F2")</strong></td></tr>
            <tr><td colspan="3" class="text-end"><strong>Paid:</strong></td><td><strong>$@invoice.PaidAmount.ToString("F2")</strong></td></tr>
            <tr><td colspan="3" class="text-end"><strong>Balance:</strong></td><td><strong class="@(invoice.BalanceDue > 0 ? "text-danger" : "text-success")">$@invoice.BalanceDue.ToString("F2")</strong></td></tr>
        </tfoot>
    </table>

    @if (invoice.BalanceDue > 0)
    {
        <h4 class="mt-4">Record Payment</h4>
        <div class="card">
            <div class="card-body">
                <EditForm Model="newPayment" OnValidSubmit="ProcessPaymentAsync" FormName="paymentForm">
                    <div class="row">
                        <div class="col-md-3 mb-2">
                            <label class="form-label">Amount</label>
                            <InputNumber class="form-control" @bind-Value="newPayment.Amount" />
                        </div>
                        <div class="col-md-3 mb-2">
                            <label class="form-label">Method</label>
                            <InputSelect class="form-select" @bind-Value="newPayment.Method">
                                @foreach (var m in Enum.GetValues<PaymentMethod>())
                                {
                                    <option value="@m">@m</option>
                                }
                            </InputSelect>
                        </div>
                        <div class="col-md-3 mb-2">
                            <label class="form-label">Reference</label>
                            <InputText class="form-control" @bind-Value="newPayment.Reference" />
                        </div>
                        <div class="col-md-3 mb-2 d-flex align-items-end">
                            <button type="submit" class="btn btn-success">Process Payment</button>
                        </div>
                    </div>
                </EditForm>
            </div>
        </div>
    }

    <h4 class="mt-4">Payment History</h4>
    @if (invoice.Payments.Any())
    {
        <table class="table table-sm">
            <thead><tr><th>Date</th><th>Amount</th><th>Method</th><th>Reference</th><th>Status</th></tr></thead>
            <tbody>
                @foreach (var p in invoice.Payments.OrderByDescending(p => p.PaymentDate))
                {
                    <tr>
                        <td>@p.PaymentDate.ToShortDateString()</td>
                        <td>$@p.Amount.ToString("F2")</td>
                        <td>@p.Method</td>
                        <td>@(p.Reference ?? "—")</td>
                        <td>@(p.IsSuccessful ? "✓" : "✗")</td>
                    </tr>
                }
            </tbody>
        </table>
    }
    else
    {
        <p class="text-muted">No payments recorded.</p>
    }
}

@code {
    [Parameter] public int Id { get; set; }

    private Invoice? invoice;
    private Payment newPayment = new() { PaymentDate = DateTime.Today };

    protected override async Task OnInitializedAsync()
    {
        invoice = await Clinic.GetInvoiceAsync(Id);
        if (invoice != null)
            newPayment.Amount = invoice.BalanceDue;
    }

    private async Task ProcessPaymentAsync()
    {
        newPayment.InvoiceId = Id;
        await Clinic.ProcessPaymentAsync(newPayment);
        invoice = await Clinic.GetInvoiceAsync(Id);
        newPayment = new Payment { PaymentDate = DateTime.Today, Amount = invoice?.BalanceDue ?? 0 };
    }

    private string GetStatusBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Draft => "bg-secondary",
        InvoiceStatus.Issued => "bg-warning",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Overdue => "bg-danger",
        _ => "bg-secondary"
    };
}
