@page "/"
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@using VetClinic.Services
@attribute [Authorize]
@inject ClinicService Clinic

<PageTitle>Dashboard - VetClinic</PageTitle>

<h1>Clinic Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <h2>@todayAppointments.Count</h2>
                <a href="/appointments" class="btn btn-primary btn-sm">View Schedule</a>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Registered Patients</h5>
                <h2>@patientCount</h2>
                <a href="/patients" class="btn btn-primary btn-sm">View Patients</a>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Unpaid Invoices</h5>
                <h2>@unpaidInvoices.Count</h2>
                <a href="/billing" class="btn btn-primary btn-sm">View Billing</a>
            </div>
        </div>
    </div>
</div>

<div class="row mt-4">
    <div class="col-md-6">
        <h4>Upcoming Appointments</h4>
        @if (todayAppointments.Any())
        {
            <table class="table table-sm">
                <thead><tr><th>Time</th><th>Patient</th><th>Reason</th></tr></thead>
                <tbody>
                    @foreach (var appt in todayAppointments.Take(5))
                    {
                        <tr>
                            <td>@appt.StartTime.ToString("HH:mm")</td>
                            <td>@appt.Patient.Name</td>
                            <td>@appt.Reason</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No appointments today.</p>
        }
    </div>
    <div class="col-md-6">
        <h4>Quick Actions</h4>
        <div class="d-grid gap-2">
            <a href="/patients/new" class="btn btn-outline-primary">Register New Patient</a>
            <a href="/appointments/new" class="btn btn-outline-primary">Schedule Appointment</a>
            <a href="/billing/new" class="btn btn-outline-primary">Create Invoice</a>
        </div>
    </div>
</div>

@code {
    private List<Appointment> todayAppointments = new();
    private List<Invoice> unpaidInvoices = new();
    private int patientCount;

    protected override async Task OnInitializedAsync()
    {
        var today = DateTime.Today;
        todayAppointments = await Clinic.GetAppointmentsAsync(today, today.AddDays(1));
        todayAppointments = todayAppointments.Where(a => a.Status == AppointmentStatus.Scheduled).ToList();
        var patients = await Clinic.GetPatientsAsync();
        patientCount = patients.Count;
        unpaidInvoices = await Clinic.GetInvoicesAsync();
        unpaidInvoices = unpaidInvoices.Where(i => i.Status == InvoiceStatus.Issued || i.Status == InvoiceStatus.Overdue).ToList();
    }
}

