@page "/patients/{Id:int}/edit"
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@using VetClinic.Services
@attribute [Authorize]
@inject ClinicService Clinic
@inject NavigationManager Nav

<PageTitle>@(Id.HasValue ? "Edit Patient" : "Register Patient") - VetClinic</PageTitle>

<h1>@(Id.HasValue ? "Edit Patient" : "Register New Patient")</h1>

<EditForm Model="patient" OnValidSubmit="SaveAsync" FormName="patientForm">
    <DataAnnotationsValidator />
    <ValidationSummary />

    <h4 class="mt-3">Owner Information</h4>
    <div class="row">
        <div class="col-md-6 mb-3">
            <label class="form-label">First Name</label>
            <InputText class="form-control" @bind-Value="owner.FirstName" />
        </div>
        <div class="col-md-6 mb-3">
            <label class="form-label">Last Name</label>
            <InputText class="form-control" @bind-Value="owner.LastName" />
        </div>
        <div class="col-md-4 mb-3">
            <label class="form-label">Phone</label>
            <InputText class="form-control" @bind-Value="owner.Phone" />
        </div>
        <div class="col-md-4 mb-3">
            <label class="form-label">Email</label>
            <InputText class="form-control" @bind-Value="owner.Email" />
        </div>
        <div class="col-md-4 mb-3">
            <label class="form-label">Address</label>
            <InputText class="form-control" @bind-Value="owner.Address" />
        </div>
    </div>

    <h4 class="mt-3">Patient Information</h4>
    <div class="row">
        <div class="col-md-4 mb-3">
            <label class="form-label">Name</label>
            <InputText class="form-control" @bind-Value="patient.Name" />
        </div>
        <div class="col-md-4 mb-3">
            <label class="form-label">Species</label>
            <InputSelect class="form-select" @bind-Value="patient.Species">
                <option value="">Select...</option>
                <option value="Dog">Dog</option>
                <option value="Cat">Cat</option>
                <option value="Bird">Bird</option>
                <option value="Rabbit">Rabbit</option>
                <option value="Reptile">Reptile</option>
                <option value="Other">Other</option>
            </InputSelect>
        </div>
        <div class="col-md-4 mb-3">
            <label class="form-label">Breed</label>
            <InputText class="form-control" @bind-Value="patient.Breed" />
        </div>
        <div class="col-md-4 mb-3">
            <label class="form-label">Date of Birth</label>
            <InputDate class="form-control" @bind-Value="patient.DateOfBirth" />
        </div>
        <div class="col-md-4 mb-3">
            <label class="form-label">Weight (kg)</label>
            <InputNumber class="form-control" @bind-Value="patient.Weight" />
        </div>
        <div class="col-md-4 mb-3">
            <label class="form-label">Microchip #</label>
            <InputText class="form-control" @bind-Value="patient.Microchip" />
        </div>
    </div>

    <button type="submit" class="btn btn-primary">@(Id.HasValue ? "Update" : "Register")</button>
    <a href="/patients" class="btn btn-secondary ms-2">Cancel</a>
</EditForm>

@code {
    [Parameter] public int? Id { get; set; }

    private Patient patient = new() { DateOfBirth = DateTime.Today.AddYears(-1) };
    private Owner owner = new();

    protected override async Task OnInitializedAsync()
    {
        if (Id.HasValue)
        {
            var existing = await Clinic.GetPatientAsync(Id.Value);
            if (existing != null)
            {
                patient = existing;
                owner = existing.Owner;
            }
        }
    }

    private async Task SaveAsync()
    {
        if (owner.Id == 0)
        {
            await Clinic.SaveOwnerAsync(owner);
        }
        patient.OwnerId = owner.Id;
        patient.Owner = owner;
        await Clinic.SavePatientAsync(patient);
        Nav.NavigateTo($"/patients/{patient.Id}");
    }
}

@page "/patients/{Id:int}"
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@using VetClinic.Services
@attribute [Authorize]
@inject ClinicService Clinic
@inject NavigationManager Nav

<PageTitle>@(patient?.Name ?? "Patient") - VetClinic</PageTitle>

@if (patient == null)
{
    <p>Loading...</p>
}
else
{
    <div class="d-flex justify-content-between align-items-center">
        <h1>@patient.Name</h1>
        <a href="/patients/@patient.Id/edit" class="btn btn-outline-secondary">Edit</a>
    </div>

    <div class="row mt-3">
        <div class="col-md-6">
            <div class="card">
                <div class="card-body">
                    <h5>Patient Info</h5>
                    <p><strong>Species:</strong> @patient.Species | <strong>Breed:</strong> @patient.Breed</p>
                    <p><strong>DOB:</strong> @patient.DateOfBirth.ToShortDateString() | <strong>Weight:</strong> @patient.Weight kg</p>
                    <p><strong>Microchip:</strong> @(patient.Microchip ?? "N/A")</p>
                </div>
            </div>
        </div>
        <div class="col-md-6">
            <div class="card">
                <div class="card-body">
                    <h5>Owner Info</h5>
                    <p><strong>Name:</strong> @patient.Owner.FirstName @patient.Owner.LastName</p>
                    <p><strong>Phone:</strong> @patient.Owner.Phone</p>
                    <p><strong>Email:</strong> @patient.Owner.Email</p>
                </div>
            </div>
        </div>
    </div>

    <div class="mt-4">
        <div class="d-flex justify-content-between align-items-center">
            <h3>Medical History</h3>
            <button class="btn btn-primary btn-sm" @onclick="ToggleNoteForm">Add Treatment Note</button>
        </div>

        @if (showNoteForm)
        {
            <div class="card mt-3">
                <div class="card-body">
                    <h5>New Treatment Note</h5>
                    <EditForm Model="newNote" OnValidSubmit="AddNoteAsync" FormName="treatmentNoteForm">
                        <div class="row">
                            <div class="col-md-6 mb-2">
                                <label class="form-label">Date</label>
                                <InputDate class="form-control" @bind-Value="newNote.Date" />
                            </div>
                            <div class="col-md-6 mb-2">
                                <label class="form-label">Veterinarian</label>
                                <InputText class="form-control" @bind-Value="newNote.VeterinarianName" />
                            </div>
                            <div class="col-md-6 mb-2">
                                <label class="form-label">Diagnosis</label>
                                <InputText class="form-control" @bind-Value="newNote.Diagnosis" />
                            </div>
                            <div class="col-md-6 mb-2">
                                <label class="form-label">Treatment</label>
                                <InputText class="form-control" @bind-Value="newNote.Treatment" />
                            </div>
                            <div class="col-md-6 mb-2">
                                <label class="form-label">Medications</label>
                                <InputText class="form-control" @bind-Value="newNote.Medications" />
                            </div>
                            <div class="col-md-6 mb-2">
                                <label class="form-label">Notes</label>
                                <InputTextArea class="form-control" @bind-Value="newNote.Notes" />
                            </div>
                        </div>
                        <button type="submit" class="btn btn-success btn-sm mt-2">Save Note</button>
                        <button type="button" class="btn btn-secondary btn-sm mt-2 ms-2" @onclick="ToggleNoteForm">Cancel</button>
                    </EditForm>
                </div>
            </div>
        }

        @if (patient.TreatmentNotes.Any())
        {
            <div class="mt-3">
                @foreach (var note in patient.TreatmentNotes)
                {
                    <div class="card mb-2">
                        <div class="card-body">
                            <div class="d-flex justify-content-between">
                                <strong>@note.Date.ToShortDateString()</strong>
                                <span class="text-muted">Dr. @note.VeterinarianName</span>
                            </div>
                            <p class="mb-1"><strong>Diagnosis:</strong> @note.Diagnosis</p>
                            <p class="mb-1"><strong>Treatment:</strong> @note.Treatment</p>
                            @if (!string.IsNullOrEmpty(note.Medications))
                            {
                                <p class="mb-1"><strong>Medications:</strong> @note.Medications</p>
                            }
                            @if (!string.IsNullOrEmpty(note.Notes))
                            {
                                <p class="mb-0 text-muted">@note.Notes</p>
                            }
                        </div>
                    </div>
                }
            </div>
        }
        else
        {
            <p class="text-muted mt-3">No treatment records yet.</p>
        }
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Patient? patient;
    private bool showNoteForm;
    private TreatmentNote newNote = new() { Date = DateTime.Today };

    protected override async Task OnInitializedAsync()
    {
        patient = await Clinic.GetPatientAsync(Id);
    }

    private void ToggleNoteForm()
    {
        showNoteForm = !showNoteForm;
        newNote = new TreatmentNote { Date = DateTime.Today, PatientId = Id };
    }

    private async Task AddNoteAsync()
    {
        newNote.PatientId = Id;
        await Clinic.AddTreatmentNoteAsync(newNote);
        patient = await Clinic.GetPatientAsync(Id);
        showNoteForm = false;
        newNote = new TreatmentNote { Date = DateTime.Today, PatientId = Id };
    }
}

