@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@using VetClinic.Services
@attribute [Authorize]
@inject ClinicService Clinic
@inject NavigationManager Nav

<PageTitle>Appointments - VetClinic</PageTitle>

<div class="d-flex justify-content-between align-items-center">
    <h1>Appointments</h1>
    <a href="/appointments/new" class="btn btn-primary">Schedule Appointment</a>
</div>

<div class="row mt-3">
    <div class="col-md-4">
        <label class="form-label">View Week Of</label>
        <InputDate class="form-control" @bind-Value="selectedDate" @bind-Value:after="LoadAppointmentsAsync" />
