@if (availabilityMessage != null)
{
    <div class="alert @(isAvailable ? "alert-success" : "alert-danger") mt-3">@availabilityMessage</div>
}

<EditForm Model="appointment" OnValidSubmit="SaveAsync" FormName="appointmentForm">
    <DataAnnotationsValidator />

    <div class="row mt-3">
        <div class="col-md-6 mb-3">
            <label class="form-label">Patient</label>
            <InputSelect class="form-select" @bind-Value="appointment.PatientId">
                <option value="0">Select patient...</option>
                @foreach (var p in patients)
                {
                    <option value="@p.Id">@p.Name (@p.Owner.LastName)</option>
                }
            </InputSelect>
        </div>
        <div class="col-md-6 mb-3">
            <label class="form-label">Veterinarian</label>
            <InputText class="form-control" @bind-Value="appointment.VeterinarianName" />
        </div>
        <div class="col-md-4 mb-3">
            <label class="form-label">Date</label>
            <InputDate class="form-control" @bind-Value="appointmentDate" @bind-Value:after="CheckAvailabilityAsync" />
        </div>
        <div class="col-md-4 mb-3">
            <label class="form-label">Start Time</label>
            <InputText class="form-control" @bind-Value="startTime" @bind-Value:after="CheckAvailabilityAsync" placeholder="HH:mm" />
        </div>
        <div class="col-md-4 mb-3">
            <label class="form-label">Duration (minutes)</label>
            <InputNumber class="form-control" @bind-Value="durationMinutes" @bind-Value:after="CheckAvailabilityAsync" />
        </div>
        <div class="col-md-12 mb-3">
            <label class="form-label">Reason</label>
            <InputText class="form-control" @bind-Value="appointment.Reason" />
        </div>
        <div class="col-md-12 mb-3">
            <label class="form-label">Notes</label>
            <InputTextArea class="form-control" @bind-Value="appointment.Notes" />
        </div>
    </div>

    <button type="submit" class="btn btn-primary" disabled="@(!isAvailable)">
        @(Id.HasValue ? "Reschedule" : "Schedule")
    </button>
    <a href="/appointments" class="btn btn-secondary ms-2">Cancel</a>
</EditForm>

@code {
    [Parameter] public int? Id { get; set; }

    private Appointment appointment = new();
    private List<Patient> patients = new();
    private DateTime appointmentDate = DateTime.Today;
    private string startTime = "09:00";
    private int durationMinutes = 30;
    private string? availabilityMessage;
    private bool isAvailable = true;

    protected override async Task OnInitializedAsync()
    {
        patients = await Clinic.GetPatientsAsync();
        if (Id.HasValue)
        {
            var existing = await Clinic.GetAppointmentAsync(Id.Value);
            if (existing != null)
            {
                appointment = existing;
                appointmentDate = existing.StartTime.Date;
                startTime = existing.StartTime.ToString("HH:mm");
                durationMinutes = (int)(existing.EndTime - existing.StartTime).TotalMinutes;
            }
        }
    }

    private async Task CheckAvailabilityAsync()
    {
        if (TimeSpan.TryParse(startTime, out var time))
        {
            var start = appointmentDate.Date + time;
            var end = start.AddMinutes(durationMinutes);
            isAvailable = await Clinic.IsTimeSlotAvailableAsync(start, end, Id);
            availabilityMessage = isAvailable ? "✓ Time slot is available" : "✗ Time slot conflicts with another appointment";
        }
    }

    private async Task SaveAsync()
    {
        if (TimeSpan.TryParse(startTime, out var time))
        {
            appointment.StartTime = appointmentDate.Date + time;
            appointment.EndTime = appointment.StartTime.AddMinutes(durationMinutes);
            await Clinic.SaveAppointmentAsync(appointment);
            Nav.NavigateTo("/appointments");
        }
    }
}

