@code {
    [Parameter] public int? Id { get; set; }

    private Appointment appointment = new();
    private List<Patient> patients = new();
    private DateTime appointmentDate = DateTime.Today;
    private string startTime = "09:00";
    private int durationMinutes = 30;
    private string? availabilityMessage;
    private bool isAvailable = true;

    protected override async Task OnInitializedAsync()
    {
        patients = await Clinic.GetPatientsAsync();
        if (Id.HasValue)
        {
            var existing = await Clinic.GetAppointmentAsync(Id.Value);
            if (existing != null)
            {
                appointment = existing;
                appointmentDate = existing.StartTime.Date;
                startTime = existing.StartTime.ToString("HH:mm");
                durationMinutes = (int)(existing.EndTime - existing.StartTime).TotalMinutes;
            }
        }
    }

    private async Task CheckAvailabilityAsync()
    {
        if (TimeSpan.TryParse(startTime, out var time))
        {
            var start = appointmentDate.Date + time;
            var end = start.AddMinutes(durationMinutes);
            isAvailable = await Clinic.IsTimeSlotAvailableAsync(start, end, Id);
            availabilityMessage = isAvailable ? "✓ Time slot is available" : "✗ Time slot conflicts with another appointment";
        }
    }

    private async Task SaveAsync()
    {
        if (TimeSpan.TryParse(startTime, out var time))
        {
            appointment.StartTime = appointmentDate.Date + time;
            appointment.EndTime = appointment.StartTime.AddMinutes(durationMinutes);
            await Clinic.SaveAppointmentAsync(appointment);
            Nav.NavigateTo("/appointments");
        }
    }
}
```

